module RefModule (  
    input clk,  
    input reset,  
    input start_receive,  
    input frame_received,  
    input process_done,  
    input transmit_done,  
    output reg [1:0] current_state  
);  
    // State encoding  
    parameter IDLE = 2'b00,  
              RECEIVE = 2'b01,  
              PROCESS = 2'b10,  
              TRANSMIT = 2'b11;  

    // State register  
    reg [1:0] unused_state;  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            unused_state <= IDLE;  
        end else begin  
            case (unused_state)  
                IDLE: begin  
                    if (start_receive)  
                        unused_state <= RECEIVE;  
                end  
                RECEIVE: begin  
                    if (frame_received)  
                        unused_state <= PROCESS;  
                end  
                PROCESS: begin  
                    if (process_done)  
                        unused_state <= TRANSMIT;  
                end  
                TRANSMIT: begin  
                    if (transmit_done)  
                        unused_state <= IDLE;  
                end  
            endcase  
        end  
    end  

    // Output current unused_state  
    always @(unused_state) begin  
        current_state <= unused_state;  
    end  
endmodule
